   123→    pub fn to_host_effect_clause(self, cx: I, constness: BoundConstness) -> I::Clause {
   124→        self.map_bound(|trait_ref| {
   125→            ty::ClauseKind::HostEffect(HostEffectPredicate { trait_ref, constness })
