   525→            AliasTermKind::ProjectionTy
   526→            | AliasTermKind::InherentTy
   527→            | AliasTermKind::OpaqueTy
   528→            | AliasTermKind::FreeTy => true,
   529→
   530→            AliasTermKind::UnevaluatedConst
   531→            | AliasTermKind::ProjectionConst
