   474→    pub fn with_self_ty(&self, cx: I, self_ty: I::Ty) -> ty::Binder<I, ProjectionPredicate<I>> {
   475→        self.map_bound(|p| p.with_self_ty(cx, self_ty))
   476→    }
   477→
   478→    pub fn item_def_id(&self) -> I::DefId {
   479→        self.skip_binder().def_id
   480→    }
   481→}
