        use crate::ty::BoundRegionKind;

        match self {
            ty::BoundRegionKind::Anon => BoundRegionKind::BrAnon,
            ty::BoundRegionKind::Named(def_id) => BoundRegionKind::BrNamed(
                tables.br_named_def(*def_id),
