            ClauseKind::WellFormed(term) => {
                crate::ty::ClauseKind::WellFormed(term.kind().stable(tables, cx))
            }
            ClauseKind::ConstEvaluatable(const_) => {
                crate::ty::ClauseKind::ConstEvaluatable(const_.stable(tables, cx))
            }
            ClauseKind::HostEffect(..) => {
